import React from 'react';
import { MemoryRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Provider } from 'react-redux';
import { store } from './store/store';
import { AppLayout } from './components/layout/AppLayout';
import { SimpleNotFoundPage } from '@linm-soft-org/linm-web-common-components';
import { isStandalone, showDevNav } from './dev/isStandalone';
import { StandaloneMockNav } from './standalone/StandaloneMockNav';
import { MemoryRouterSync } from './router/MemoryRouterSync';

const DevPage = React.lazy(() => import('./dev/DevPage'));

// ── Danh Mục (dm) ──────────────────────────────────────────────────────────
const VatTuPage       = React.lazy(() => import('./pages/dm/VatTuPage'));
const DoiTuongPage      = React.lazy(() => import('./pages/dm/DoiTuongPage'));
const NhomVatTuPage     = React.lazy(() => import('./pages/dm/NhomVatTuPage'));
const NhomDoiTuongPage  = React.lazy(() => import('./pages/dm/NhomDoiTuongPage'));
const DonViCoSoPage   = React.lazy(() => import('./pages/dm/DonViCoSoPage'));
const DonViTinhPage   = React.lazy(() => import('./pages/dm/DonViTinhPage'));
const DanhMucKhoPage  = React.lazy(() => import('./pages/dm/DanhMucKhoPage'));
const PhongBanPage    = React.lazy(() => import('./pages/dm/PhongBanPage'));
const TaiKhoanPage    = React.lazy(() => import('./pages/dm/TaiKhoanPage'));
const TyGiaPage       = React.lazy(() => import('./pages/dm/TyGiaPage'));
const NgoaiTePage     = React.lazy(() => import('./pages/dm/NgoaiTePage'));
const TaiKhoanNganHangPage = React.lazy(() => import('./pages/dm/TaiKhoanNganHangPage'));
const ChiPhiPage      = React.lazy(() => import('./pages/dm/ChiPhiPage'));
const CcdcPage        = React.lazy(() => import('./pages/dm/CcdcPage'));
const CcdcQuanLyPage  = React.lazy(() => import('./pages/dm/CcdcQuanLyPage'));
const HoTroTscdPage   = React.lazy(() => import('./pages/dm/HoTroTscdPage'));
const PhanBoPage      = React.lazy(() => import('./pages/dm/PhanBoPage'));
const KetChuyenPage   = React.lazy(() => import('./pages/dm/KetChuyenPage'));
const DinhKhoanNghiepVuPage = React.lazy(() => import('./pages/dm/DinhKhoanNghiepVuPage'));

// ── System ──────────────────────────────────────────────────────────────────
const SystemSettingsPage = React.lazy(() => import('./pages/system/SystemSettingsPage'));
const VoucherCodeFormatPage = React.lazy(() => import('./pages/system/VoucherCodeFormatPage'));
const VoucherSetupPage       = React.lazy(() => import('./pages/system/VoucherSetupPage'));
const MasterCatalogCodeSetupPage = React.lazy(() => import('./pages/system/MasterCatalogCodeSetupPage/MasterCatalogCodeSetupPage'));

const Suspense = ({ children }: { children: React.ReactNode }) => (
  <React.Suspense fallback={<div style={{ padding: '2rem' }}>Đang tải...</div>}>
    {children}
  </React.Suspense>
);
const AppShell = () => (
  <>
    {isStandalone && <StandaloneMockNav />}
    <AppLayout />
  </>
);

const Root: React.FC = () => (
  <Provider store={store}>
    <Router
      initialEntries={[
        typeof window !== 'undefined'
          ? (window.location.pathname + window.location.search || '/')
          : '/',
      ]}
      initialIndex={0}
      future={{ v7_startTransition: true, v7_relativeSplatPath: true }}
    >
      <MemoryRouterSync />
      <Routes>
        <Route path="/" element={isStandalone ? <AppShell /> : <AppLayout />}>
          {showDevNav && (
            <>
              <Route index element={<Navigate to="/dev" replace />} />
              <Route path="dev" element={<Suspense><DevPage /></Suspense>} />
            </>
          )}
          {/* Danh Mục */}
          <Route path="dm" element={<Navigate to="dm/vat-tu" replace />} />
          <Route path="dm/vat-tu"         element={<Suspense><VatTuPage /></Suspense>} />
          <Route path="dm/doi-tuong"      element={<Suspense><DoiTuongPage /></Suspense>} />
          <Route path="dm/doi-tac"        element={<Navigate to="/dm/doi-tuong" replace />} />
          <Route path="dm/nhom-vat-tu"    element={<Suspense><NhomVatTuPage /></Suspense>} />
          <Route path="dm/nhom-doi-tuong"  element={<Suspense><NhomDoiTuongPage /></Suspense>} />
          <Route path="dm/nhom-doi-tac"   element={<Navigate to="/dm/nhom-doi-tuong" replace />} />
          <Route path="dm/don-vi"         element={<Navigate to="/dm/don-vi-co-so" replace />} />
          <Route path="dm/don-vi-co-so"   element={<Suspense><DonViCoSoPage /></Suspense>} />
          <Route path="dm/don-vi-tinh"    element={<Suspense><DonViTinhPage /></Suspense>} />
          <Route path="dm/danh-muc-kho"   element={<Suspense><DanhMucKhoPage /></Suspense>} />
          <Route path="dm/phong-ban"      element={<Suspense><PhongBanPage /></Suspense>} />
          <Route path="dm/tai-khoan"      element={<Suspense><TaiKhoanPage /></Suspense>} />
          <Route path="dm/ty-gia"         element={<Suspense><TyGiaPage /></Suspense>} />
          <Route path="dm/ngoai-te"       element={<Suspense><NgoaiTePage /></Suspense>} />
          <Route path="dm/tai-khoan-ngan-hang" element={<Suspense><TaiKhoanNganHangPage /></Suspense>} />
          <Route path="dm/chi-phi"        element={<Suspense><ChiPhiPage /></Suspense>} />
          <Route path="dm/ccdc"           element={<Suspense><CcdcPage /></Suspense>} />
          <Route path="dm/ccdc-quan-ly"   element={<Suspense><CcdcQuanLyPage /></Suspense>} />
          <Route path="dm/ho-tro-tscd"    element={<Suspense><HoTroTscdPage /></Suspense>} />
          <Route path="dm/phan-bo"        element={<Suspense><PhanBoPage /></Suspense>} />
          <Route path="dm/ket-chuyen"     element={<Suspense><KetChuyenPage /></Suspense>} />
          <Route path="dm/dinh-khoan-nghiep-vu" element={<Suspense><DinhKhoanNghiepVuPage /></Suspense>} />

          {/* System */}
          <Route path="system" element={<Navigate to="system/settings" replace />} />
          <Route path="system/users" element={<Navigate to="/system/settings" replace />} />
          <Route path="system/roles" element={<Navigate to="/system/settings" replace />} />
          <Route path="system/settings" element={<Suspense><SystemSettingsPage /></Suspense>} />
          <Route path="system/voucher-setup" element={<Suspense><VoucherSetupPage /></Suspense>} />
          <Route path="system/master-code-setup" element={<Suspense><MasterCatalogCodeSetupPage /></Suspense>} />
          <Route path="system/voucher-code-format" element={<Suspense><VoucherCodeFormatPage /></Suspense>} />

          <Route path="*" element={<SimpleNotFoundPage showDevNav={showDevNav} homePath="/dm/vat-tu" />} />
        </Route>
      </Routes>
    </Router>
  </Provider>
);

export default Root;
